import React, { useState, useEffect, useMemo } from 'react';

const theme = {
  colors: {
    primary: '#8b5cf6',
    background: '#0a0a0a',
    surface: '#111111',
    surfaceAlt: '#1a1a1a',
    border: '#2a2a2a',
    text: '#fafafa',
    textSecondary: '#a1a1aa',
    textMuted: '#52525b',
    blue: '#38bdf8',
    yellow: '#fbbf24',
    pink: '#f472b6',
    green: '#a3e635',
    orange: '#fb923c',
    purple: '#c084fc',
  },
  font: "'JetBrains Mono', monospace",
};

const C0 = 3;
const GROWTH_RATE = 2;
const NUM_LAYERS = 4;

const GROUP_COLORS = [
  '#38bdf8',
  '#fb923c',
  '#a3e635',
  '#f472b6',
  '#c084fc',
];

function relu(v) { return Math.max(0, v); }

export default function App() {
  const [layerShown, setLayerShown] = useState(0);
  const [playing, setPlaying] = useState(false);
  const [animPhase, setAnimPhase] = useState('idle'); // 'relu', 'conv', 'concat', 'idle'

  useEffect(() => {
    if (!playing) return;
    if (layerShown >= NUM_LAYERS) { setPlaying(false); setAnimPhase('idle'); return; }
    let t1, t2, t3, t4;
    setAnimPhase('relu');
    t1 = setTimeout(() => setAnimPhase('conv'), 600);
    t2 = setTimeout(() => setAnimPhase('concat'), 1200);
    t3 = setTimeout(() => { setLayerShown(l => l + 1); setAnimPhase('idle'); }, 1900);
    return () => { clearTimeout(t1); clearTimeout(t2); clearTimeout(t3); clearTimeout(t4); };
  }, [playing, layerShown]);

  function handlePlay() {
    if (layerShown >= NUM_LAYERS) { setLayerShown(0); setAnimPhase('idle'); setTimeout(() => setPlaying(true), 50); }
    else setPlaying(p => !p);
  }

  function handleReset() { setPlaying(false); setLayerShown(0); setAnimPhase('idle'); }

  function handleStep() {
    if (layerShown >= NUM_LAYERS) return;
    setAnimPhase('relu');
    setTimeout(() => setAnimPhase('conv'), 400);
    setTimeout(() => setAnimPhase('concat'), 900);
    setTimeout(() => { setLayerShown(l => l + 1); setAnimPhase('idle'); }, 1400);
  }

  const channelGroups = useMemo(() => {
    const groups = [{ label: 'Input', count: C0, color: GROUP_COLORS[0] }];
    for (let l = 0; l < layerShown; l++) {
      groups.push({ label: 'L' + (l + 1), count: GROWTH_RATE, color: GROUP_COLORS[l + 1] });
    }
    return groups;
  }, [layerShown]);

  const totalChannels = C0 + layerShown * GROWTH_RATE;
  const nextKernelIn = totalChannels;
  const nextLayerIdx = layerShown + 1;
  const MAX_CHANNELS = C0 + NUM_LAYERS * GROWTH_RATE;

  // SVG layout
  const SVG_W = 560;
  const SVG_H = 280;
  const BAR_Y = 20;
  const BAR_H = 48;
  const BAR_X0 = 20;
  const BAR_TOTAL_W = SVG_W - 40;
  const UNIT_W = BAR_TOTAL_W / MAX_CHANNELS;

  // Draw channel bar
  function renderBar(groups, y, h, opacity = 1) {
    let x = BAR_X0;
    const rects = [];
    groups.forEach((g, gi) => {
      for (let c = 0; c < g.count; c++) {
        const w = UNIT_W - 1.5;
        const isInput = gi === 0;
        rects.push(
          <g key={gi + '-' + c}>
            <rect x={x} y={y} width={w} height={h}
              fill={g.color} opacity={opacity} rx={2} />
            {c === 0 && g.count > 0 && (
              <text x={x + (g.count * UNIT_W) / 2 - 1} y={y + h / 2 + 4}
                textAnchor="middle" fontSize={10} fill="#000" fontWeight="700"
                style={{ pointerEvents: 'none' }}>
                {g.label}
              </text>
            )}
          </g>
        );
        x += UNIT_W;
      }
    });
    // Ghost cells for remaining
    const filled = groups.reduce((s, g) => s + g.count, 0);
    for (let c = filled; c < MAX_CHANNELS; c++) {
      rects.push(
        <rect key={'ghost' + c} x={x} y={y} width={UNIT_W - 1.5} height={h}
          fill="#1e293b" opacity={0.6} rx={2} />
      );
      x += UNIT_W;
    }
    return rects;
  }

  // Arrow lines from all current channels -> conv box -> new channels
  const CONV_BOX_Y = 110;
  const CONV_BOX_H = 36;
  const CONV_BOX_X = SVG_W / 2 - 70;
  const CONV_BOX_W = 140;
  const NEW_CHAN_Y = 195;
  const NEW_CHAN_H = 38;

  // x center of existing channel bar
  const existingBarCX = BAR_X0 + (totalChannels * UNIT_W) / 2;
  // x center of new channels (they appear at end of bar)
  const newChanX0 = BAR_X0 + totalChannels * UNIT_W;
  const newChanCX = newChanX0 + (GROWTH_RATE * UNIT_W) / 2;

  const isRunning = layerShown < NUM_LAYERS;
  const reluActive = animPhase === 'relu' || animPhase === 'conv' || animPhase === 'concat';
  const convActive = animPhase === 'conv' || animPhase === 'concat';
  const concatActive = animPhase === 'concat';

  function phaseColor(active) {
    return active ? theme.colors.yellow : theme.colors.border;
  }

  const barCY = BAR_Y + BAR_H / 2;

  return (
    <div style={{
      background: theme.colors.background,
      minHeight: '100vh',
      fontFamily: theme.font,
      color: theme.colors.text,
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      padding: '16px 12px',
    }}>
      <div style={{ width: '100%', maxWidth: 600 }}>

        {/* Header */}
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 12 }}>
          <div>
            <div style={{ fontSize: 16, fontWeight: 700, color: theme.colors.text }}>DenseNet Dense Block</div>
            <div style={{ fontSize: 11, color: theme.colors.textSecondary, marginTop: 2 }}>Each layer receives ALL previous feature maps</div>
          </div>
          <div style={{ display: 'flex', gap: 8 }}>
            <button onClick={handlePlay} style={{
              background: playing ? theme.colors.orange : theme.colors.primary,
              color: '#fff', border: 'none', borderRadius: 6,
              padding: '6px 14px', fontSize: 12, cursor: 'pointer', fontFamily: theme.font, fontWeight: 600
            }}>{playing ? 'Pause' : (layerShown >= NUM_LAYERS ? 'Replay' : 'Play')}</button>
            <button onClick={handleReset} style={{
              background: theme.colors.surfaceAlt, color: theme.colors.textSecondary,
              border: '1px solid ' + theme.colors.border, borderRadius: 6,
              padding: '6px 10px', fontSize: 12, cursor: 'pointer', fontFamily: theme.font
            }}>Reset</button>
          </div>
        </div>

        {/* Main SVG Visualization */}
        <div style={{ background: theme.colors.surface, borderRadius: 12, padding: '12px 8px', marginBottom: 10 }}>
          <svg width="100%" viewBox={`0 0 ${SVG_W} ${SVG_H}`} style={{ display: 'block' }}>

            {/* Label: Feature Tensor */}
            <text x={BAR_X0} y={BAR_Y - 6} fontSize={10} fill={theme.colors.textSecondary}>Feature Tensor  ({totalChannels} ch)</text>

            {/* Channel bar */}
            {renderBar(channelGroups, BAR_Y, BAR_H)}

            {/* Bracket under current channels */}
            {isRunning && (
              <g opacity={reluActive ? 1 : 0.35} style={{ transition: 'opacity 0.4s' }}>
                <line x1={BAR_X0} y1={BAR_Y + BAR_H + 6} x2={BAR_X0 + totalChannels * UNIT_W - 1} y2={BAR_Y + BAR_H + 6}
                  stroke={reluActive ? theme.colors.yellow : theme.colors.textMuted} strokeWidth={1.5} />
                <line x1={BAR_X0} y1={BAR_Y + BAR_H + 2} x2={BAR_X0} y2={BAR_Y + BAR_H + 10}
                  stroke={reluActive ? theme.colors.yellow : theme.colors.textMuted} strokeWidth={1.5} />
                <line x1={BAR_X0 + totalChannels * UNIT_W - 1} y1={BAR_Y + BAR_H + 2}
                  x2={BAR_X0 + totalChannels * UNIT_W - 1} y2={BAR_Y + BAR_H + 10}
                  stroke={reluActive ? theme.colors.yellow : theme.colors.textMuted} strokeWidth={1.5} />
                <text x={BAR_X0 + (totalChannels * UNIT_W) / 2} y={BAR_Y + BAR_H + 22}
                  textAnchor="middle" fontSize={9.5}
                  fill={reluActive ? theme.colors.yellow : theme.colors.textMuted}>
                  {`All ${nextKernelIn} ch -> ReLU`}
                </text>
              </g>
            )}

            {/* Arrow from bar to conv box */}
            {isRunning && (
              <g opacity={convActive ? 1 : 0.22} style={{ transition: 'opacity 0.4s' }}>
                <line
                  x1={existingBarCX} y1={BAR_Y + BAR_H + 28}
                  x2={SVG_W / 2} y2={CONV_BOX_Y - 3}
                  stroke={theme.colors.yellow} strokeWidth={1.5}
                  strokeDasharray={convActive ? '0' : '4 3'}
                />
                <polygon
                  points={`${SVG_W / 2 - 4},${CONV_BOX_Y - 10} ${SVG_W / 2 + 4},${CONV_BOX_Y - 10} ${SVG_W / 2},${CONV_BOX_Y - 2}`}
                  fill={theme.colors.yellow}
                />
              </g>
            )}

            {/* Convolution box */}
            {isRunning && (
              <g>
                <rect x={CONV_BOX_X} y={CONV_BOX_Y} width={CONV_BOX_W} height={CONV_BOX_H}
                  fill={convActive ? '#27272a' : '#18181b'}
                  stroke={convActive ? theme.colors.yellow : theme.colors.border}
                  strokeWidth={convActive ? 1.5 : 1}
                  rx={6}
                  style={{ transition: 'all 0.3s' }}
                />
                <text x={SVG_W / 2} y={CONV_BOX_Y + 13} textAnchor="middle" fontSize={10}
                  fill={convActive ? theme.colors.yellow : theme.colors.textMuted}
                  style={{ transition: 'fill 0.3s' }}>
                  Conv2D (3x3, same pad)
                </text>
                <text x={SVG_W / 2} y={CONV_BOX_Y + 28} textAnchor="middle" fontSize={9}
                  fill={convActive ? theme.colors.textSecondary : theme.colors.textMuted}
                  style={{ transition: 'fill 0.3s' }}>
                  kernel: ({nextKernelIn} -> {GROWTH_RATE} ch)
                </text>
              </g>
            )}

            {/* Arrow from conv to new channels */}
            {isRunning && (
              <g opacity={concatActive ? 1 : 0.22} style={{ transition: 'opacity 0.4s' }}>
                <line
                  x1={SVG_W / 2} y1={CONV_BOX_Y + CONV_BOX_H + 2}
                  x2={newChanCX} y2={NEW_CHAN_Y - 3}
                  stroke={GROUP_COLORS[layerShown + 1] || theme.colors.green}
                  strokeWidth={1.5}
                />
                <polygon
                  points={`${newChanCX - 4},${NEW_CHAN_Y - 10} ${newChanCX + 4},${NEW_CHAN_Y - 10} ${newChanCX},${NEW_CHAN_Y - 2}`}
                  fill={GROUP_COLORS[layerShown + 1] || theme.colors.green}
                />
              </g>
            )}

            {/* New channels preview */}
            {isRunning && (
              <g opacity={concatActive ? 1 : 0.18} style={{ transition: 'opacity 0.4s' }}>
                {Array.from({ length: GROWTH_RATE }).map((_, i) => (
                  <g key={i}>
                    <rect
                      x={newChanX0 + i * UNIT_W}
                      y={NEW_CHAN_Y}
                      width={UNIT_W - 1.5}
                      height={NEW_CHAN_H}
                      fill={GROUP_COLORS[layerShown + 1] || theme.colors.green}
                      rx={2}
                    />
                    {i === 0 && (
                      <text
                        x={newChanX0 + (GROWTH_RATE * UNIT_W) / 2}
                        y={NEW_CHAN_Y + NEW_CHAN_H / 2 + 4}
                        textAnchor="middle" fontSize={10} fill="#000" fontWeight="700">
                        {'L' + nextLayerIdx}
                      </text>
                    )}
                  </g>
                ))}
                <text
                  x={newChanX0 + (GROWTH_RATE * UNIT_W) / 2}
                  y={NEW_CHAN_Y + NEW_CHAN_H + 14}
                  textAnchor="middle" fontSize={9.5}
                  fill={concatActive ? GROUP_COLORS[layerShown + 1] : theme.colors.textMuted}
                  style={{ transition: 'fill 0.3s' }}>
                  +{GROWTH_RATE} new channels
                </text>
                {/* Concat arrow going up */}
                <line
                  x1={newChanCX}
                  y1={NEW_CHAN_Y - 12}
                  x2={newChanCX}
                  y2={BAR_Y + BAR_H + 2}
                  stroke={concatActive ? GROUP_COLORS[layerShown + 1] : theme.colors.textMuted}
                  strokeWidth={1}
                  strokeDasharray="3 2"
                  style={{ transition: 'stroke 0.3s' }}
                />
              </g>
            )}

            {/* Done state */}
            {!isRunning && (
              <g>
                <text x={SVG_W / 2} y={140} textAnchor="middle" fontSize={14}
                  fill={theme.colors.green} fontWeight="700">
                  Dense Block Complete!
                </text>
                <text x={SVG_W / 2} y={162} textAnchor="middle" fontSize={11}
                  fill={theme.colors.textSecondary}>
                  {C0} + {NUM_LAYERS} x {GROWTH_RATE} = {MAX_CHANNELS} total channels
                </text>
                <text x={SVG_W / 2} y={185} textAnchor="middle" fontSize={10}
                  fill={theme.colors.textMuted}>
                  Each layer saw ALL previous feature maps (dense connectivity)
                </text>
              </g>
            )}

            {/* Phase label */}
            {isRunning && animPhase !== 'idle' && (
              <text x={SVG_W / 2} y={SVG_H - 6} textAnchor="middle" fontSize={11}
                fill={theme.colors.yellow} style={{ transition: 'opacity 0.3s' }}>
                {animPhase === 'relu' && 'Step 1: Apply ReLU to all current channels'}
                {animPhase === 'conv' && 'Step 2: Convolve to produce ' + GROWTH_RATE + ' new channels'}
                {animPhase === 'concat' && 'Step 3: Concatenate - new channels become part of tensor!'}
              </text>
            )}
          </svg>
        </div>

        {/* Stats row */}
        <div style={{ display: 'flex', gap: 8, marginBottom: 10 }}>
          {[0, 1, 2, 3, 4].map(l => {
            const ch = C0 + l * GROWTH_RATE;
            const active = l === layerShown;
            const done = l < layerShown;
            return (
              <div key={l} onClick={() => { if (!playing) { setLayerShown(l); setAnimPhase('idle'); } }}
                style={{
                  flex: 1, background: active ? '#1e1b4b' : theme.colors.surfaceAlt,
                  border: '1px solid ' + (active ? theme.colors.primary : (done ? theme.colors.green + '55' : theme.colors.border)),
                  borderRadius: 8, padding: '8px 4px', textAlign: 'center',
                  cursor: playing ? 'default' : 'pointer',
                  transition: 'all 0.3s',
                }}>
                <div style={{ fontSize: 10, color: done ? theme.colors.green : (active ? theme.colors.primary : theme.colors.textMuted), marginBottom: 2 }}>
                  {l === 0 ? 'Input' : 'After L' + l}
                </div>
                <div style={{ fontSize: 16, fontWeight: 700, color: active ? theme.colors.primary : (done ? theme.colors.green : theme.colors.textMuted), fontFamily: theme.font }}>
                  {ch}
                </div>
                <div style={{ fontSize: 9, color: theme.colors.textMuted }}>ch</div>
              </div>
            );
          })}
        </div>

        {/* Step button */}
        {isRunning && !playing && (
          <button onClick={handleStep} style={{
            width: '100%', background: theme.colors.surfaceAlt,
            border: '1px solid ' + theme.colors.primary,
            color: theme.colors.primary, borderRadius: 8,
            padding: '9px', fontSize: 12, cursor: 'pointer',
            fontFamily: theme.font, fontWeight: 600, marginBottom: 10,
          }}>
            {'Run Layer ' + nextLayerIdx + '  (kernel: ' + nextKernelIn + ' -> ' + GROWTH_RATE + ' ch, stride=1, same-pad)'}
          </button>
        )}

        {/* Legend */}
        <div style={{ display: 'flex', gap: 8, marginBottom: 10, flexWrap: 'wrap' }}>
          {channelGroups.map((g, i) => (
            <div key={i} style={{ display: 'flex', alignItems: 'center', gap: 5 }}>
              <div style={{ width: 12, height: 12, borderRadius: 2, background: g.color }} />
              <span style={{ fontSize: 10, color: theme.colors.textSecondary }}>
                {g.label} ({g.count} ch)
              </span>
            </div>
          ))}
        </div>

        {/* Key insight */}
        <div style={{
          background: theme.colors.surfaceAlt,
          borderLeft: '3px solid ' + theme.colors.primary,
          borderRadius: '0 8px 8px 0', padding: '9px 12px',
          fontSize: 11, color: theme.colors.textSecondary, lineHeight: 1.6,
        }}>
          <span style={{ color: theme.colors.primary, fontWeight: 700 }}>Key insight: </span>
          {layerShown === 0 &&
            'A regular CNN: each layer sees only the PREVIOUS layer. DenseNet: every layer sees ALL previous layers. Click "Run Layer 1" to start building.'}
          {layerShown === 1 &&
            'Layer 1 received ' + C0 + ' channels and output ' + GROWTH_RATE + ' new ones. Its kernel shape was (3,3,' + C0 + ',' + GROWTH_RATE + '). Now the tensor has ' + (C0 + GROWTH_RATE) + ' channels total.'}
          {layerShown === 2 &&
            'Layer 2\'s kernel needed ' + (C0 + GROWTH_RATE) + ' input channels - it sees the original input AND Layer 1 output! Kernel: (3,3,' + (C0 + GROWTH_RATE) + ',' + GROWTH_RATE + ').'}
          {layerShown === 3 &&
            'Layer 3 gets ' + (C0 + 2 * GROWTH_RATE) + ' channels. Feature reuse: early edge detectors stay available deep in the network. This fights the vanishing gradient problem too!'}
          {layerShown === 4 &&
            'Final: ' + MAX_CHANNELS + ' channels = ' + C0 + ' (input) + ' + NUM_LAYERS + ' x ' + GROWTH_RATE + ' (growth). Dense connectivity means rich feature reuse with fewer parameters than a regular deep CNN.'}
        </div>
      </div>
    </div>
  );
}
